```ts
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { apiClient } from '@/lib/api/client';
import { withToast } from '@/lib/api/mutation-helpers';
import { ENDPOINTS } from '@/lib/api/endpoints';

export function useDepartmentsQuery() {
  return useQuery({
    queryKey: ['departments'],
    queryFn: ({ signal }) => apiClient.get<{ departments: string[] }>(ENDPOINTS.departments.list, { signal }),
    staleTime: 15 * 60_000, // 15 min
  });
}

export function useDepartmentPermissionsQuery(employeeId?: string) {
  return useQuery({
    queryKey: ['department-permissions', employeeId],
    queryFn: ({ signal }) =>
      apiClient.get(`${ENDPOINTS.departments.permissions}?employee_id=${encodeURIComponent(employeeId ?? '')}`, { signal }),
    enabled: Boolean(employeeId),
    staleTime: 60_000,
  });
}

export function useGrantPermissionMutation() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (input: { employee_id: string; departments: string[] }) =>
      apiClient.post(ENDPOINTS.departments.permissions, input),
    ...withToast({
      success: 'Đã cấp quyền',
      onSuccess: () => {
        qc.invalidateQueries({ queryKey: ['department-permissions'] });
        qc.invalidateQueries({ queryKey: ['departments'] });
      },
    }),
  });
}
```

