import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { apiClient } from '@/lib/api/client';
import { withToast } from '@/lib/api/mutation-helpers';
import { ENDPOINTS } from '@/lib/api/endpoints';

export function useAttendanceListQuery(filters: { salary_month?: string; department?: string; page?: number; limit?: number }) {
  return useQuery({
    queryKey: ['attendance', filters],
    queryFn: ({ signal }) => {
      const params = new URLSearchParams();
      Object.entries(filters).forEach(([k, v]) => v != null && params.set(k, String(v)));
      return apiClient.get(`${ENDPOINTS.attendance.list}?${params.toString()}`, { signal });
    },
    staleTime: 60_000,
  });
}

export function useAttendanceImportMutation() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (formData: FormData) => apiClient.post(ENDPOINTS.attendance.import, formData),
    ...withToast({
      success: 'Đã import',
      onSuccess: () => qc.invalidateQueries({ queryKey: ['attendance'] }),
    }),
  });
}
