1245:   delete (globalThis as any).fetch;
1246:   delete (globalThis as any).Request;
1247:   delete (globalThis as any).Response;
1248:   delete (globalThis as any).Headers;
1249:   // eslint-disable-next-line @typescript-eslint/no-require-imports
1250:   delete require.cache[require.resolve('whatwg-fetch')];
1251:   // eslint-disable-next-line @typescript-eslint/no-require-imports
1252:   require('whatwg-fetch');
